import React from 'react';
import styled from 'styled-components';
import {Outlet} from "react-router-dom";
import urlArrImg from "../1redux/arrImg.js";

const SHomeMain = styled.div`
grid-area:1/1/13/13;
display: grid;
grid-template-columns:repeat(12, 8.333%);  
grid-template-rows:repeat(12, 8.333%); 
background: red ;
color: black ;
font-family: 'TopSecretWoff2' ;

`

const SSlide = styled.div`
grid-area:1/1/13/13;
display: grid;
background: black ; 
`
const PoolImg = styled.div`
grid-area:1/1/13/13;
display: flex;
flex-direction: row;
flex-wrap: wrap;
justify-content: space-around ;
overflow:scroll;
`
const Img = styled.img`
height: 50px;
width:75px;

`


let i = 0;

let url = urlArrImg.map((el) => {
  i++
return { src:`../1redux/imagess/${el}`, key:`${i}`}
});

const Slide = () => {
  return (
     <SSlide>
     <PoolImg>
   {url.map((el) => (<Img key={el.key} src={el.src} alt={el.key}  />))} 
   </PoolImg>
    </SSlide>
)};


const HomeMain = () => {
  return (
<SHomeMain>

<Slide/>

<Outlet />
</SHomeMain>
  );
};

export default HomeMain;
